// ---------- helpers ----------
  function throttle(fn, waitMs) {
    let last = 0, timer = 0, pendingArgs = null;
    return (...args) => {
      const now = Date.now();
      const remaining = waitMs - (now - last);
      if (remaining <= 0) {
        last = now;
        fn(...args);
      } else {
        pendingArgs = args;
        clearTimeout(timer);
        timer = setTimeout(() => { last = Date.now(); fn(...pendingArgs); }, remaining);
      }
    };
  }

/**
