def sha1(filename):
    fd = io.open(filename, 'rb')
    h = hashlib.sha1()
    data = True
    while data:
        data = fd.read(4096)
        if data:
            h.update(data)
    fd.close()

    return h.hexdigest()

def sha1sum(path):
    """Calculates the sha1 sum of a given file without loading it at once in memory"""
    sha1sum = hashlib.sha1()
    with open(path, 'rb') as fd:
        block = fd.read(2**16)
        while len(block) != 0:
            sha1sum.update(block)
            block = fd.read(2**16)
    return sha1sum.hexdigest().zfill(40)

