        prefix, raw = raw[1:].split(' ', 1)
    parts = raw.split(' ', 1)
    command = parts[0]
    if len(parts) > 1:
        ti = parts[1].find(' :')
        if ti >= 0:
            params = parts[1][:ti].split()
            params.append(parts[1][ti+2:])
        else:
            params = parts[1].split()
